export enum QuestionType {
  MULTIPLE_CHOICE = 'multiple_choice',
  TRUE_FALSE = 'true_false',
  SHORT_ANSWER = 'short_answer',
  ESSAY = 'essay'
}

export interface Answer {
  id: string;
  text: string;
  isCorrect: boolean;
}

export interface Question {
  id: string;
  type: QuestionType;
  text: string;
  points: number;
  answers: Answer[];
  feedback?: string;
}

export interface QuizData {
  title: string;
  description: string;
  questions: Question[];
}

export interface ProcessingState {
  status: 'idle' | 'reading' | 'analyzing' | 'generating_zip' | 'done' | 'error';
  message: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { QuizData, QuestionType } from "../types";

export const parseMarkdownToQuiz = async (markdownText: string): Promise<QuizData> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key ontbreekt. Controleer je configuratie.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Je bent een expert in het maken van educatieve toetsen voor Canvas LMS.
    Analyseer de volgende tekst (Markdown) en extraheer een structuur voor een quiz.

    De tekst kan vragen bevatten, antwoorden, en eventueel punten.
    Probeer zo goed mogelijk het type vraag te bepalen:
    - Multiple Choice (één goed antwoord uit meerdere opties)
    - True/False (Waar/Niet waar)
    - Short Answer (Kort antwoord, invuloefening)
    - Essay (Open vraag)

    Als er geen punten staan vermeld, gebruik dan 1 punt als standaard.
    Als er geen titel is, bedenk een passende titel op basis van de inhoud.
    Zorg dat elke vraag minimaal één correct antwoord heeft (tenzij het een essay vraag is).

    Invoer tekst:
    ${markdownText}
  `;

  // We definiëren een strict schema voor de output zodat we het direct kunnen gebruiken.
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING, description: "Titel van de quiz" },
          description: { type: Type.STRING, description: "Korte beschrijving of instructie" },
          questions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING, description: "De vraagstelling" },
                type: { 
                  type: Type.STRING, 
                  enum: [
                    QuestionType.MULTIPLE_CHOICE, 
                    QuestionType.TRUE_FALSE, 
                    QuestionType.SHORT_ANSWER,
                    QuestionType.ESSAY
                  ] 
                },
                points: { type: Type.NUMBER, description: "Aantal punten" },
                feedback: { type: Type.STRING, description: "Algemene feedback voor de student" },
                answers: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      text: { type: Type.STRING, description: "Antwoord tekst" },
                      isCorrect: { type: Type.BOOLEAN, description: "Is dit het juiste antwoord?" }
                    },
                    required: ["text", "isCorrect"]
                  }
                }
              },
              required: ["text", "type", "points", "answers"]
            }
          }
        },
        required: ["title", "questions"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Geen antwoord ontvangen van AI.");

  try {
    const rawData = JSON.parse(text);

    // Post-processing om ID's toe te voegen die we nodig hebben voor React keys en QTI
    const processedData: QuizData = {
      ...rawData,
      questions: rawData.questions.map((q: any) => ({
        ...q,
        id: crypto.randomUUID(),
        answers: q.answers.map((a: any) => ({
          ...a,
          id: crypto.randomUUID()
        }))
      }))
    };

    return processedData;
  } catch (e) {
    console.error("Parse error", e);
    throw new Error("Kon de AI respons niet verwerken tot een geldige quiz structuur.");
  }
};

import JSZip from 'jszip';
import { QuizData, Question, QuestionType } from '../types';

// Helper to escape XML characters
const escapeXml = (unsafe: string) => {
  return unsafe.replace(/[<>&'"]/g, (c) => {
    switch (c) {
      case '<': return '&lt;';
      case '>': return '&gt;';
      case '&': return '&amp;';
      case '\'': return '&apos;';
      case '"': return '&quot;';
      default: return c;
    }
  });
};

// Generates the unique identifier for the manifest
const generateManifestId = () => `MANIFEST-${crypto.randomUUID()}`;

// 1. Generate imsmanifest.xml
const generateManifest = (quiz: QuizData, questionIds: string[]) => {
  const manifestId = generateManifestId();
  const resources = questionIds.map(id => `
    <resource identifier="resource_${id}" type="imsqti_item_xmlv2p1" href="items/${id}.xml">
      <file href="items/${id}.xml"/>
    </resource>
  `).join('\n');

  // Add the assessment resource
  const assessmentResourceId = `resource_assessment_${crypto.randomUUID()}`;
  const assessmentHref = "assessment/assessment.xml";

  return `<?xml version="1.0" encoding="UTF-8"?>
<manifest xmlns="http://www.imsglobal.org/xsd/imscp_v1p1"
          xmlns:imsmd="http://www.imsglobal.org/xsd/imsmd_v1p2"
          xmlns:imsqti="http://www.imsglobal.org/xsd/imsqti_v2p1"
          xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
          xsi:schemaLocation="http://www.imsglobal.org/xsd/imscp_v1p1 http://www.imsglobal.org/xsd/imscp_v1p1.xsd http://www.imsglobal.org/xsd/imsmd_v1p2 http://www.imsglobal.org/xsd/imsmd_v1p2p2.xsd http://www.imsglobal.org/xsd/imsqti_v2p1 http://www.imsglobal.org/xsd/imsqti_v2p1.xsd"
          identifier="${manifestId}">
  <metadata>
    <schema>IMS Content</schema>
    <schemaversion>1.1.3</schemaversion>
    <imsmd:lom>
      <imsmd:general>
        <imsmd:title>
          <imsmd:langstring xml:lang="en">${escapeXml(quiz.title)}</imsmd:langstring>
        </imsmd:title>
        <imsmd:description>
           <imsmd:langstring xml:lang="en">${escapeXml(quiz.description || "Generated by AI QTI Tool")}</imsmd:langstring>
        </imsmd:description>
      </imsmd:general>
    </imsmd:lom>
  </metadata>
  <organizations/>
  <resources>
    <resource identifier="${assessmentResourceId}" type="imsqti_test_xmlv2p1" href="${assessmentHref}">
      <file href="${assessmentHref}"/>
      ${questionIds.map(id => `<dependency identifierref="resource_${id}"/>`).join('\n      ')}
    </resource>
    ${resources}
  </resources>
</manifest>`;
};

// 2. Generate Assessment XML (The Test definition)
const generateAssessment = (quiz: QuizData, questions: Question[]) => {
  const testId = `TEST-${crypto.randomUUID()}`;
  const partId = `PART-${crypto.randomUUID()}`;
  const sectionId = `SECTION-${crypto.randomUUID()}`;

  const assessmentItems = questions.map(q => `
        <assessmentItemRef identifier="itemref_${q.id}" href="../items/${q.id}.xml" fixed="false"/>
  `).join('\n');

  return `<?xml version="1.0" encoding="UTF-8"?>
<assessmentTest xmlns="http://www.imsglobal.org/xsd/imsqti_v2p1"
                xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
                xsi:schemaLocation="http://www.imsglobal.org/xsd/imsqti_v2p1 http://www.imsglobal.org/xsd/imsqti_v2p1.xsd"
                identifier="${testId}" title="${escapeXml(quiz.title)}">
  <testPart identifier="${partId}" navigationMode="linear" submissionMode="individual">
    <assessmentSection identifier="${sectionId}" title="Main Section" visible="true">
      ${assessmentItems}
    </assessmentSection>
  </testPart>
</assessmentTest>`;
};

// 3. Generate Item XML (Individual Questions)
const generateItem = (q: Question) => {
  const responseId = `RESPONSE_${q.id}`;

  // -- Multiple Choice & True/False Logic --
  if (q.type === QuestionType.MULTIPLE_CHOICE || q.type === QuestionType.TRUE_FALSE) {
    const correctAnswers = q.answers.filter(a => a.isCorrect);
    // If no correct answer found, fallback to first (should act differently but for safety)
    const validCorrectId = correctAnswers.length > 0 ? correctAnswers[0].id : q.answers[0]?.id;

    return `<?xml version="1.0" encoding="UTF-8"?>
<assessmentItem xmlns="http://www.imsglobal.org/xsd/imsqti_v2p1"
                xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
                xsi:schemaLocation="http://www.imsglobal.org/xsd/imsqti_v2p1 http://www.imsglobal.org/xsd/imsqti_v2p1.xsd"
                identifier="${q.id}" title="${escapeXml(q.text.substring(0, 50))}..." adaptive="false" timeDependent="false">
  <responseDeclaration identifier="RESPONSE" cardinality="single" baseType="identifier">
    <correctResponse>
      <value>${validCorrectId}</value>
    </correctResponse>
  </responseDeclaration>
  <outcomeDeclaration identifier="SCORE" cardinality="single" baseType="float">
    <defaultValue>
      <value>0</value>
    </defaultValue>
  </outcomeDeclaration>
  <itemBody>
    <choiceInteraction responseIdentifier="RESPONSE" shuffle="false" maxChoices="1">
      <prompt>${escapeXml(q.text)}</prompt>
      ${q.answers.map(a => `
      <simpleChoice identifier="${a.id}">${escapeXml(a.text)}</simpleChoice>
      `).join('')}
    </choiceInteraction>
  </itemBody>
</assessmentItem>`;
  }

  // -- Essay / Short Answer Logic (Simplified to extendedTextInteraction) --
  // Canvas treats Essay and Short Answer differently but structurally extendedTextInteraction covers open input.
  return `<?xml version="1.0" encoding="UTF-8"?>
<assessmentItem xmlns="http://www.imsglobal.org/xsd/imsqti_v2p1"
                xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
                xsi:schemaLocation="http://www.imsglobal.org/xsd/imsqti_v2p1 http://www.imsglobal.org/xsd/imsqti_v2p1.xsd"
                identifier="${q.id}" title="${escapeXml(q.text.substring(0, 50))}..." adaptive="false" timeDependent="false">
  <responseDeclaration identifier="RESPONSE" cardinality="single" baseType="string"/>
  <outcomeDeclaration identifier="SCORE" cardinality="single" baseType="float">
    <defaultValue>
      <value>0</value>
    </defaultValue>
  </outcomeDeclaration>
  <itemBody>
    <extendedTextInteraction responseIdentifier="RESPONSE">
      <prompt>${escapeXml(q.text)}</prompt>
    </extendedTextInteraction>
  </itemBody>
</assessmentItem>`;
};


export const createQtiZip = async (quiz: QuizData): Promise<Blob> => {
  const zip = new JSZip();

  // 1. Manifest
  const questionIds = quiz.questions.map(q => q.id);
  zip.file("imsmanifest.xml", generateManifest(quiz, questionIds));

  // 2. Assessment File
  zip.file("assessment/assessment.xml", generateAssessment(quiz, quiz.questions));

  // 3. Item Files
  quiz.questions.forEach(q => {
    zip.file(`items/${q.id}.xml`, generateItem(q));
  });

  return await zip.generateAsync({ type: "blob" });
};

import React from 'react';
import { QuizData, QuestionType } from '../types';
